export type YamlFieldName =
  | "key"
  | "value"
export type VueFieldName = never

/** Every named node type across the built-in grammars — the `find` domain. */
export type NodeType =
  | JavascriptNodeType
  | TypescriptNodeType
  | TsxNodeType
  | HtmlNodeType
  | CssNodeType
  | YamlNodeType
  | VueNodeType

/** Every node type, named or anonymous — the `RichNode.type` domain. */
export type NodeTypeAll =
  | JavascriptNodeTypeAll
  | TypescriptNodeTypeAll
  | TsxNodeTypeAll
  | HtmlNodeTypeAll
  | CssNodeTypeAll
  | YamlNodeTypeAll
  | VueNodeTypeAll

/** Every field name across the built-in grammars. */
export type FieldName =
  | JavascriptFieldName
  | TypescriptFieldName
  | TsxFieldName
  | HtmlFieldName
  | CssFieldName
  | YamlFieldName
  | VueFieldName

// Per-grammar projections — `…Of<G>` selects one grammar (and distributes over a union of
// grammars). `…Of<GrammarId>` equals the combined union, so they're drop-in for the defaults.
/** The a node type valid in grammar `G` — e.g. `NodeTypeOf<'typescript'>`. */
export type NodeTypeOf<G extends 'javascript' | 'typescript' | 'tsx' | 'html' | 'css' | 'yaml' | 'vue'> =
  G extends 'javascript' ? JavascriptNodeType :
  G extends 'typescript' ? TypescriptNodeType :
  G extends 'tsx' ? TsxNodeType :
  G extends 'html' ? HtmlNodeType :
  G extends 'css' ? CssNodeType :
  G extends 'yaml' ? YamlNodeType :
  G extends 'vue' ? VueNodeType :
  never

/** The a node type (named or anonymous) valid in grammar `G` — e.g. `NodeTypeAllOf<'typescript'>`. */
export type NodeTypeAllOf<G extends 'javascript' | 'typescript' | 'tsx' | 'html' | 'css' | 'yaml' | 'vue'> =
  G extends 'javascript' ? JavascriptNodeTypeAll :
  G extends 'typescript' ? TypescriptNodeTypeAll :
  G extends 'tsx' ? TsxNodeTypeAll :
  G extends 'html' ? HtmlNodeTypeAll :
  G extends 'css' ? CssNodeTypeAll :
  G extends 'yaml' ? YamlNodeTypeAll :
  G extends 'vue' ? VueNodeTypeAll :
  never

/** The a field name valid in grammar `G` — e.g. `FieldNameOf<'typescript'>`. */
export type FieldNameOf<G extends 'javascript' | 'typescript' | 'tsx' | 'html' | 'css' | 'yaml' | 'vue'> =
  G extends 'javascript' ? JavascriptFieldName :
  G extends 'typescript' ? TypescriptFieldName :
  G extends 'tsx' ? TsxFieldName :
  G extends 'html' ? HtmlFieldName :
  G extends 'css' ? CssFieldName :
  G extends 'yaml' ? YamlFieldName :
  G extends 'vue' ? VueFieldName :
  never

